// TestUpsertBatch_PopulatesWebhooksTable verifies that UpsertBatch
// dispatches paginated items into both the generic resources table AND the
// typed webhooks table. Regression for issue #268: before the fix, paginated
// syncs only filled the generic resources table, so domain commands that
// query the typed table saw zero rows.
func TestUpsertBatch_PopulatesWebhooksTable(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "test-001"}`),
		json.RawMessage(`{"id": "test-002"}`),
		json.RawMessage(`{"id": "test-003"}`),
	}
	if _, _, err := s.UpsertBatch("webhooks", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "webhooks").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "webhooks")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count webhooks: %v", err)
	}
	if typed != len(items) {
		t.Fatalf("webhooks count = %d, want %d (typed table not populated by UpsertBatch)", typed, len(items))
	}
}

// TestSearch_TypeFilter pins the --type filter semantics: passing a non-empty
// resourceType narrows the FTS lookup to that type. Regression for the
// previously-silent --type flag.
func TestSearch_TypeFilter(t *testing.T) {
	dir := t.TempDir()
	s, err := Open(filepath.Join(dir, "data.db"))
	if err != nil {
		t.Fatalf("Open: %v", err)
	}
	defer s.Close()

	// Two resources of different types, same searchable content.
	if _, _, err := s.UpsertBatch("videos", []json.RawMessage{
		json.RawMessage(`{"id":"v-1","name":"Mario clone demo"}`),
	}); err != nil {
		t.Fatalf("UpsertBatch videos: %v", err)
	}
	if _, _, err := s.UpsertBatch("playlists", []json.RawMessage{
		json.RawMessage(`{"id":"p-1","name":"Mario clone collection"}`),
	}); err != nil {
		t.Fatalf("UpsertBatch playlists: %v", err)
	}

	// No filter -> both rows match.
	allHits, err := s.Search("Mario", "", 50)
	if err != nil {
		t.Fatalf("Search unfiltered: %v", err)
	}
	if len(allHits) != 2 {
		t.Fatalf("unfiltered search = %d hits, want 2", len(allHits))
	}

	// --type videos -> just the video.
	vidHits, err := s.Search("Mario", "videos", 50)
	if err != nil {
		t.Fatalf("Search videos: %v", err)
	}
	if len(vidHits) != 1 {
		t.Fatalf("--type videos = %d hits, want 1", len(vidHits))
	}

	// --type playlists -> just the playlist.
	plHits, err := s.Search("Mario", "playlists", 50)
	if err != nil {
		t.Fatalf("Search playlists: %v", err)
	}
	if len(plHits) != 1 {
		t.Fatalf("--type playlists = %d hits, want 1", len(plHits))
	}

	// --type bogus -> zero hits.
	noneHits, err := s.Search("Mario", "nonexistent", 50)
	if err != nil {
		t.Fatalf("Search nonexistent: %v", err)
	}
	if len(noneHits) != 0 {
		t.Fatalf("--type nonexistent = %d hits, want 0", len(noneHits))
	}
}

// TestResolveByName_RejectsUnsafeFieldNames pins the allowlist guard added
// to ResolveByName. Crafted field names containing path metacharacters must
// be skipped silently (treated as a no-match) rather than interpolated into
// a json_extract Sprintf where they could escape the SQL path expression.
func TestResolveByName_RejectsUnsafeFieldNames(t *testing.T) {
	dir := t.TempDir()
	s, err := Open(filepath.Join(dir, "data.db"))
	if err != nil {
		t.Fatalf("Open: %v", err)
	}
	defer s.Close()

	if _, _, err := s.UpsertBatch("videos", []json.RawMessage{
		json.RawMessage(`{"id":"v-1","name":"hello"}`),
	}); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	// Safe field — should match the row by name.
	got, err := s.ResolveByName("videos", "hello", "name")
	if err != nil {
		t.Fatalf("ResolveByName(name): %v", err)
	}
	if got != "v-1" {
		t.Fatalf("ResolveByName(name) = %q, want v-1", got)
	}

	// Crafted field with quote/path metacharacters — must be rejected
	// before reaching the json_extract Sprintf, so the function ends up
	// with zero matched rows and returns the canonical "not found"
	// error. The injection payload must never produce a v-1 match.
	unsafe := []string{
		"name')) UNION SELECT data FROM resources--",
		"name'.injected",
		"name; DROP TABLE resources",
		"name with spaces",
		"name.subfield",
		"",
	}
	for _, field := range unsafe {
		got, err := s.ResolveByName("videos", "hello", field)
		if err == nil {
			t.Fatalf("ResolveByName(%q) = %q, want error (unsafe field name should produce no match)", field, got)
		}
		if got != "" {
			t.Fatalf("ResolveByName(%q) returned id %q on error path, want empty string", field, got)
		}
	}

	// Mixed safe + unsafe still resolves via the safe field only.
	got, err = s.ResolveByName("videos", "hello", "name'.injected", "name")
	if err != nil {
		t.Fatalf("ResolveByName(unsafe+safe): %v", err)
	}
	if got != "v-1" {
		t.Fatalf("ResolveByName(unsafe+safe) = %q, want v-1", got)
	}
}
